from elasticsearch import Elasticsearch
from elasticsearch.helpers import scan
import json

class DynamicAggregationClient:
    def __init__(self, hosts=['localhost:9200']):
        self.es = Elasticsearch(hosts=hosts)
    
    def execute_dynamic_aggregation(self, index, script_code, params=None):
        """
        Execute dynamic script aggregation using Elasticsearch Script API
        """
        if params is None:
            params = {}
            
        # Construct the aggregation with dynamic script
        aggregation_body = {
            "aggs": {
                "dynamic_result": {
                    "scripted_metric": {
                        "init_script": "state.count = 0",
                        "map_script": script_code,
                        "combine_script": "return state.count",
                        "reduce_script": "int sum = 0; for (int i = 0; i < states.length; i++) { sum += states[i]; } return sum;"
                    }
                }
            }
        }
        
        try:
            response = self.es.search(
                index=index,
                body=aggregation_body,
                request_cache=False
            )
            
            return response
            
        except Exception as e:
            raise Exception(f"Aggregation execution failed: {str(e)}")
    
    def execute_script_aggregation(self, index, script_code, field=None, params=None):
        """
        Alternative method using painless script aggregation
        """
        if params is None:
            params = {}
            
        if field:
            aggregation_body = {
                "aggs": {
                    "scripted_aggregation": {
                        "terms": {
                            "script": {
                                "source": script_code,
                                "lang": "painless"
                            },
                            "field": field
                        }
                    }
                }
            }
        else:
            aggregation_body = {
                "aggs": {
                    "scripted_aggregation": {
                        "value_count": {
                            "script": {
                                "source": script_code,
                                "lang": "painless"
                            }
                        }
                    }
                }
            }
            
        try:
            response = self.es.search(
                index=index,
                body=aggregation_body,
                request_cache=False
            )
            
            return response
            
        except Exception as e:
            raise Exception(f"Script aggregation failed: {str(e)}")

